const Q_PHYSICS_2009=[{"id": "objective>Physics>2009>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The values of x, y, and z respectively in the expression M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">z</span> for the universal gravitational constant G are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.-3.-2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1.3.-2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1.2.-3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-2.-1.3</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F = GMm/R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>; GMm = FR<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  <br/>  G = FR<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/Mm = MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> x L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/ M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>  <br/>  = M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1-2</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> = M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>  <br/>  x = -1, y = 3 , z = -2</div>", "topic": "MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>2009>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I.Diameter of a small ball bearing  <br/>  II.Thickness of a piece of paper.  <br/>  III.Diameter of a measuring cylinder. <br/> IV.Length of a piece of wire. <br/> Which of the above can be measured using a micrometer screw gauge?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV only  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A micrometer screw gauge is a precision measuring instrument used to measure small lengths with high accuracy. It can measure objects with dimensions in the range of millimeters to micrometers.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2009>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An aircraft attempts to fly due north at 100kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. If the wind blows against it from east to west at 60kmh-1, its resultant velocity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">117kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, N31<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">127kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, N31<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">117kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, N31<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">127kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, N31<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>W</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using Pythagoras theorem;  <br/>  100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = (resultant velocity i.e RV<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  <br/>  10000 + 3600 = RV<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>; 13600 = RV<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  <br/>  RV = 13600 = 116.7kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> = 117kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> 8nl* tan q/100 60 = 0.6; tan q = 0.6 = 30.96  <br/> 31<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> = N31<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>W; 117kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, N31<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>W.</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2009>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the acceleration between two points on a velocity-time graph which has coordinates (10s, 15ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>) and (20s, 35m s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.75ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.50ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.00ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">(10s 15ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)(20s 35ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)  <br/> Using gradient formular  <br/>  gradient = y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> / x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>  <br/>  x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 10, y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 15  <br/>  x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 20, y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 35  <br/>  = 35 - 15 / 20 - 10 = 20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>/10s;  <br/>  2ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> x s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> = 2ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>.</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2009>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A car accelerates uniformly from rest at 4ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>. How far will it travel in the fifth complete second?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100m\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50m   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">32m   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">18m</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0,</td><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>,</td><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">?</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ut</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">at<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">After</td><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">s,</td><td style=\"text-align:center;\">it</td><td style=\"text-align:center;\">will</td><td style=\"text-align:center;\">travel</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">s(4)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">32</td><td style=\"text-align:center;\">m</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">After</td><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">s,</td><td style=\"text-align:center;\">it</td><td style=\"text-align:center;\">will</td><td style=\"text-align:center;\">travel</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">s(5)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50</td><td style=\"text-align:center;\">m</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">The</td><td style=\"text-align:center;\">distance,</td><td style=\"text-align:center;\">s,</td><td style=\"text-align:center;\">it</td><td style=\"text-align:center;\">will</td><td style=\"text-align:center;\">travel</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">fifth</td><td style=\"text-align:center;\">complete</td><td style=\"text-align:center;\">second</td><td style=\"text-align:center;\">is</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">s(5)</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">s(4)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">32</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">18</td><td style=\"text-align:center;\">m</td></tr></table></div> <br/> </div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2009>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the diagrams below shows the position at which a small ball-bearing is in neutral equilibrium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The position at which the small ball-bearing is at neutral equilibrium is: <br/>  <br/> <img src=\"2009/opt4.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY"}, {"id": "objective>Physics>2009>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body of mass 12kg travelling at 4.2ms-1 collides with a second body of mass 18kg at rest. Calculate their common velocity if the two bodies coalesce after collision.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.4ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.1ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.7ms</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = (M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)V  <br/>  (12 x 4.2) - (18 x 0) = (12 + 18)v  <br/> 50.4 - 0 = 30v;  <br/>  30v = 50.4; v = 50.4/30  <br/>  = 1.68  <br/> = 1.7ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2009>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bullet fired vertically upward from a gun held 2.0m above the ground reaches its maximum height in 4.0 s. calculate its initial velocity. <br/> [g = 10ms-2]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10ms-1\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8ms-1\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40ms-1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20ms-1\t</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The initial velocity of the bullet can be calculated using the equation of motion: v = u + gt. Since the bullet reaches its maximum height in 4.0 s, at this point its final velocity (v) is 0. We can rearrange the equation to find the initial velocity (u): u = v - gt = 0 - (-10 * 4) = 40 ms-1. Therefore, the initial velocity of the bullet is 40 ms-1.</div>", "topic": "MOTION: MOTION UNDER GRAVITY"}, {"id": "objective>Physics>2009>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. The motion of the tyres of a moving car.  <br/>  II. The motion of a loaded test tube oscillating vertically.  <br/>  III.  The beating of the heart.  <br/>  IV.  A stone tied to a string and whirled round.  <br/>  V. The motion of the pistons in a gasoline engine.  <br/> Which of the motions above is simple harmonic?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III, IV and V only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and V only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Simple harmonic motion is a type of periodic motion where the restoring force is directly proportional to the displacement. It is characterized by its sinusoidal nature. The motion of a loaded test tube oscillating vertically (II), the beating of the heart (III), and the motion of the pistons in a gasoline engine (V) can be considered as examples of simple harmonic motion.</div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2009>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a cage containing a truck of coal weighing 750kg is raised to a height of 90m in 1 minute, what is the total power expended?  <br/>  [g = 10ms-2]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">11.50 kW\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.60 kW </div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.25 kW\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.10 kw </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Power = workdone or energy expended / time taken  <br/>  P = W/t = F x s / t = Ma x s / t = 750 x 10 x 90 / 60  <br/>  P = 11250W;  <br/>  P = 11.25KW.</div>", "topic": "WORK, ENERGY AND POWER: POWER"}, {"id": "objective>Physics>2009>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of mass 80kg is pulled on a horizontal rough ground by a force of 500 <br/> N. Find the coefficient of static friction.  <br/> [g = 10ms-2]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.8\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.6</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">N = F/R, Limiting frictional force, F = 500N  <br/> Normal reaction R = 80kg = 80 x 10 = 800N  <br/>  N = F/R  = 500/800 = 5/8 = 0.625  <br/>  = 0.6. </div>", "topic": "FRICTION"}, {"id": "objective>Physics>2009>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a heavy barrel is rolled up a plane inclined at 30 degrees to the horizontal, its velocity ratio will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.1\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.2\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<hr size=\"1\" />R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />sinθ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />sin30</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />0.5</td></tr></table></div> <br/> = 2.</div>", "topic": "SIMPLE MACHINES"}, {"id": "objective>Physics>2009>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The terminal velocity of a ball-bearing falling through a viscous fluid is reached when the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">upthrust is equal to the weight of the ball</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ball accelerates uniformly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">upthrust is equal to the velocity of the ball</div>", "<div style=\"font-family:Cambria;font-size:17px;\">velocity is uniform</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The terminal velocity of a ball-bearing falling through a viscous fluid is reached when the downward force (weight) on the ball equals the upward force (drag) on the ball. At this point, the ball stops accelerating and falls at a constant speed, or uniform velocity. Therefore, the correct answer is 'velocity is uniform.'</div>", "topic": "FRICTION : VISCOSITY AND TERMINAL VELOCITY"}, {"id": "objective>Physics>2009>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Density of the liquid  <br/>  II. Acceleration due to gravity  <br/>  III. Type of container of the liquid  <br/>  IV. The constituents of the liquid.  <br/>  Which of the above conditions will NOT affect the pressure of fluids?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and III only\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV only\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II on</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pressure of a fluid at a given depth is determined by the density of the fluid, the depth, and the acceleration due to gravity. The type of container does not affect the pressure, as pressure at a point in a fluid is the same in all directions. The constituents of the liquid can affect its density, and therefore the pressure. So, the conditions that will NOT affect the pressure of fluids are III. Type of container of the liquid and IV. The constituents of the liquid.</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2009>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The diagram above represents the graph of the force (F) applied in stretching a spiral spring against the corresponding extension (X). The force constant of the spring is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">By gradient = y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> / x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 120 - 40 / 6 - 2  <br/>  = 80N/4m  <br/>  = 20Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. </div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2009>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a load of mass 10N stretches a cord 1.2cm, what is the total work done? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.6  x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total workdone = 1/2F x e i.e convert 1.20cm to m  <br/>  = 1/2 x 10 x 1.2/100 = 5 x 0.012 = 0.06  <br/>  = 6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J.</div>", "topic": "ELASTICITY : WORK DONE IN SPRINGS AND ELASTIC STRINGS"}, {"id": "objective>Physics>2009>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A plastic sphere floats in water with 50% of its volume submerged. If it floats in glycerine with 40% of its volume submerged, the density of the glycerine is ......  <br/>  [density of water = 1000kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1400kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1250kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">500kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1000kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Density = mass/volume  <br/>  % volume of plastic sphere in water = 50%  <br/>  % volume of plastic in glycerine = 40%  <br/> D = MV; 1000 = Mass /50  <br/>  Mass = 100 x 50 = 50000kg  <br/> D = M/V = 50000/40 = 1250Kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>.</div>", "topic": "LIQUIDS AT REST : LAW OF FLOATATION"}, {"id": "objective>Physics>2009>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The thermometer whose reading is indicated by a change in colour of its thermometric property is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bi-metallic strip thermometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thermocouple</div>", "<div style=\"font-family:Cambria;font-size:17px;\">platinum resistance thermometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">optical pyrometer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an optical pyrometer, a brightness comparison is made to measure the temperature. As a measure of the reference temperature, a color change with the growth in temperature is taken. The device compares the brightness produced by the radiation of the object whose temperature is to be measured, with that of a reference temperature. The reference temperature is produced by a lamp whose brightness can be adjusted till its intensity becomes equal to the brightness of the source object.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2009>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At 4°C, the volume of a fixed mass of water is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">constant\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximum\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water is most dense and thus has the least volume at 4 degrees Celsius. This is due to the unique properties of water. As it cools from room temperature, it becomes denser until it reaches 4°C. Below 4°C, it becomes less dense. Therefore, at 4°C, the volume of a fixed mass of water is at its minimum.</div>", "topic": "THERMAL EXPANSION : LIQUIDS"}, {"id": "objective>Physics>2009>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pressure of two moles of an ideal gas at a temperature of 27<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C and volume <br/> 10-2m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> is .....  <br/>  [R = 8.313 J mol-1 K-1]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.99 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.80 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.98 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>     </div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.80 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">PV = nRT; <br/> P = nRT/V = 2 x 8.313 x 300 / 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>  <br/>  = 4987.8/0.01 = 498780 Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>  <br/> = 4.99 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2009>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric heater rated 220V, 1000W is immersed into a bucket full of water. Calculate the mass of water if the temperature changes from 300C to 1000C and the current flows for 300 seconds.  <br/>  [Specific heat capacity of water = 4200 J kg-1 K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>].</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.28kg\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">42.86kg\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.02kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.14kg</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">MCθ = IVt;  <br/>  M = IVt/Cq  <br/>  But P = IV; I = P/V = 1000/220 = 4.55A <br/>  M = IVt/Ct = 4.55 x 220 x 300 / 4200 x 70   <br/> = 1.02kg.</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2009>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the pressure of the vapour on top of an enclosed liquid is equal to the atmospheric pressure, what will be the temperature of the liquid enclosed?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Room temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Boiling point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Freezing point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Standard temperature</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It will be the boiling point. boiling oint is the temperature at which the saturated vapour pressure is equal to the atmospheric pressure </div>", "topic": "CHANGE OF STATE : EVAPORATION AND BOILING"}, {"id": "objective>Physics>2009>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A heating coil rated 1000W is used to boil off completely 2kg of boiling water. The time required to boil off the water is.....  <br/>  [specific latent heat of vaporization of water = 2.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.15 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> s\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.15 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> s\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> s</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pt = ML; t = ML/P = 2 x 2.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> / 1000 = 4.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> / 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/> t = 4.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>.</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF VAPORIZATION"}, {"id": "objective>Physics>2009>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">It is observed that water will wet a clean glass because the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cohesion of water to glass is stronger than the cohesion of water molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adhesion of water molecules is weaker than the cohesion of water to glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cohesion of water to glass is weaker than the cohesion of water molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adhesion of water molecules is stronger than the cohesion of water molecules</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water does not wet waxed surfaces because the cohesive forces within the drops are stronger than the adhesive forces between the drops and the wax. Water wets glass and spreads out on it because the adhesive forces between the liquid and the glass are stronger than the cohesive forces within the water. This study falls under <strong>Surface Tension.</strong></div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2009>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man standing 2m from a charcoal fire is warmed mainly by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">convection\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduction</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The man gets warm by radiation , radiation is the transfer of heat without passing through any material medium.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2009>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The wave phenomenon demonstrated in the diagram above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reflection\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffraction\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is diffraction, diffraction is the spreading of waves after passing through a tiny aperture or opening </div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2009>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A progressive wave is represented by y = 10sin(1000π t - πx/34). Two layers of the wave separated by 153cm have a phase difference of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">270<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">180<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">y = 10sin(<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">100πt</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">34</span> - <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">πx</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">34</span>) <br/>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2πx<hr size=\"1\" />λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">πx<hr size=\"1\" />34</td></tr></table></div> <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />34</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">68cm</td></tr></table></div> <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2πx<hr size=\"1\" />λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π &#215; 153<hr size=\"1\" />68</td></tr></table></div> <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9π<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9 &#215; 180<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span><hr size=\"1\" />2</td><td style=\"text-align:center;\">(π</td><td style=\"text-align:center;\">rad</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">180<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">810<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2(360<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>)</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></td><td style=\"text-align:center;\">(2πn</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">or</td><td style=\"text-align:center;\">360<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>n</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">θ)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Where</td><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">is</td><td style=\"text-align:center;\">1,</td><td style=\"text-align:center;\">2,</td><td style=\"text-align:center;\">3,</td><td style=\"text-align:center;\">........</td></tr></table></div></div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2009>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Metal cables are used as telephone wires because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they are cheap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are sourced locally</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the speed of sound in them is very low</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the speed of sound in them is very high</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The speed of sound in them is very high in the sense that sound is converter to electic signal and sent via the wires.</div>", "topic": "PROPAGATION OF SOUND WAVES : SPEED OF SOUND"}, {"id": "objective>Physics>2009>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Musical instruments playing the same note can be distinguished from one another owing to the differences in their </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quality\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pitch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intensity\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loudness</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In simple terms, timbre/quality is what makes a particular musical sound different from another, even when they have the same pitch and loudness. For instance, it is the difference between a guitar and a piano playing the same note at the same loudness.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : QUALITY, PITCH, INTENSITY AND LOUDNESS"}, {"id": "objective>Physics>2009>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a light wave has a wavelength of 500nm in air, what is the frequency of the wave? .....  <br/>  [c = 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span> ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span> Hz         </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span> Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">12</span> Hz\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span> Hz</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The frequency of a wave is given by the speed of light divided by the wavelength. Given that the speed of light (c) is 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span> ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and the wavelength (λ) is 500nm or 500 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-9</span> m, the frequency (f) can be calculated as follows: f = c/λ = (3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span> ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>) / (500 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-9</span> m) = 6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span> Hz.</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2009>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Moon.  <br/>  II. Sun.  <br/>  III.  Street light.  <br/> IV.  Stars.  <br/>  Which of the above is a natural source of light?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Sun and Stars are natural sources of light. They emit light due to the nuclear fusion reactions happening in them. The Moon, however, does not emit light but reflects light from the Sun. Therefore, the Moon, Sun, and Stars are natural sources of light. Street light is a man-made source of light.</div>", "topic": "LIGHT ENERGY : SOURCE OF LIGHT"}, {"id": "objective>Physics>2009>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object is placed 5cm from the pole of a concave mirror. If the focal length of the mirror is 10cm, what is the image distance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10cm in front of the mirror</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5cm in front of the mirror</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10cm behind the mirror</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5cm behind the mirror</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1/f = 1/v + 1/u ; 1/10 = 1/v + 1/5; 1/10 = 5+v /5v  <br/>  10(5 + v) = 5v ; 50 + 10v = 5v  <br/>  10v - 5v = -50  , 5v = -50 ; v = -50/5  <br/>  v = -10cm;  <br/> v = 10cm behind the mirror.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : USE OF THE MIRROR FORMULA"}, {"id": "objective>Physics>2009>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the position of an object placed in front of a convex mirror having focal length of 12cm such that an image is formed 6cm away from the mirror.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.0cm   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0cm  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0cm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">?,</td><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-12cm</td><td style=\"text-align:center;\">(convex</td><td style=\"text-align:center;\">mirror),</td><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-6cm</td><td style=\"text-align:center;\">(virtual</td><td style=\"text-align:center;\">image)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />12</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />12</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />12</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12cm</td></tr></table></div></div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : USE OF THE MIRROR FORMULA"}, {"id": "objective>Physics>2009>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the refractive index of crown glass is 1.51, its critical angle is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">48.6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">22.5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">41.5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">45.0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">n = 1/sin c ; 1.51/1 = 1/sin c ; 1.51 sin c = 1  <br/> sin c = 1/1.51; sin c =0.6623; c = sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>0.6623  <br/> c = 41.47<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>  <br/> = 41.5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>.</div>", "topic": "REFRACTION OF LIGHT THROUGH : GLASS PRISM"}, {"id": "objective>Physics>2009>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When light passes through two media x and y of refractive indices 1.51 and 1.33 respectively, the speed of light in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">x is same as in y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">x and y is same as in vacuum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">x is higher than in y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">y is higher than in x</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The speed of light in a medium is inversely proportional to its refractive index. Therefore, the medium with the lower refractive index will have a higher speed of light. Since the refractive index of y (1.33) is less than that of x (1.51), the speed of light in y is higher than in x. Therefore, the correct option is 4.</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2009>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A near-sighted student has a near point of 0.1m and a focal length of 5.0cm. What is the student's far point?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.100m\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.000m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.125m\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.100m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V = 0.1m; F = 5.0 cm  <br/>  V = 10cm ; f = 5.0cm  <br/> 1/f = 1/v + 1/u ; 1/5 = 1/10 + 1/u ; r/5 - 1/10 = 1/u ;  <br/>  2-1/10 = 1/u; 1/10 = 1/u ;  <br/> u = 10cm.</div>", "topic": "OPTICAL INSTRUMENTS : NEAR AND FAR POINTS"}, {"id": "objective>Physics>2009>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of the human eye to focus objects on the retina is referred to as the power of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">interference\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accommodation  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">superposition</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The accommodation reflex is a reflex action of the eye, in response to focusing on a near object, then looking at distant object (and vice versa), comprising coordinated changes in vergence, lens shape and pupil size (accommodation).</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2009>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a secondary colour?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Blue\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Orange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Green</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A color produced by mixing two additive primary colors in equal proportions. Orange is a secondary colour.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>2009>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If negative charges are induced on an electroscope and a positively charged rod <br/> is brought near the cap of the electroscope, the leaves will </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">close up</div>", "<div style=\"font-family:Cambria;font-size:17px;\">become positively charged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">become negatively charged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">open further</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If negative charges are induced on an electroscope and a positively charged rod <br/> is brought near the cap of the electroscope, the leaves will close up.</div>", "topic": "ELECTROSTATICS : ELECTROSCOPE"}, {"id": "objective>Physics>2009>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  Calculate the e.m.f. of the cell in the above circuit if its internal resistance is negligible. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">12V\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8V\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2V\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">36V</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1/R = 1/R1 + 1/R2 = 1/3 + 1/6 <br/> = 3/6 <br/> R = 6/3 = 2 <br/> E = I(R + r) = 4(2 + 0) = 8v </div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2009>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric lamp marked 240V, 60W is left to operate for an hour. How much energy is generated by the filament?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.86 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> J\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.56 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.80 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> J\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.16 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">W = VIt, P = IV, 60 = 240 x I, I = 60/240 = 1/4A, W = VIt , = 240 x 1/4 x 60 x 60  <br/>  = 216,000  <br/> = 2.16 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>J.</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2009>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A band of 500 rectangular loops of wire of area 20cm by 20cm, encloses a region of magnetic field which changes from 1.0T to 0.4T within 5 seconds, calculate the induced e.m.f.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.60V\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24.00V\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.24V </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.40V</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">N = 500 loops, Area = 20cm by 20cm  <br/>  θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = B x A, Area = 400cm, ∴ 10000cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 1m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  <br/> 400cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = x  <br/> x = 400/10000 = 0.04m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>; θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = B x A  <br/>  = 1.0 x 0.04 = 0.04wb  <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = B x A = 0.4 x 0.04 = 0.06wb  <br/> Δθ = (0.04 - 0.06)wb = 0.024wb,  <br/>  ∴ E = Ndθ/dt = 500 x 0.024 / 5  <br/> = 100 x 0.024 = 2.40v.</div>", "topic": "ELECTROMAGNETIC INDUCTION"}, {"id": "objective>Physics>2009>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two coils x and y are arranged co-axially. If coil x carries a clockwise current and is free to move, which of the figures below depicts the direction of the induced current in coil y?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\">None</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If coil X carries a clockwise current, it produces a magnetic field directed into the page (using the right-hand rule for solenoids). <br/> If coil X is free to move, it will experience a force due to its interaction with coil Y. Depending on the relative motion, electromagnetic induction occurs in coil Y according to Lenz's Law, which states that the induced current opposes the change causing it. <br/> ·\tIf coil X moves towards coil Y, the flux through Y increases, and Y will induce a current to oppose the increase. This means the induced current in Y must produce a field opposing that of X, which would be out of the page. To achieve this, the induced current in Y must be counterclockwise. <br/> ·\tIf coil X moves away from coil Y, the flux through Y decreases, and Y will induce a current to oppose the decrease by reinforcing the field of X, which is into the page. This means the induced current in Y must be clockwise. <br/>  <br/> <strong>Conclusion:</strong> <br/> The direction of the induced current in coil Y depends on the motion of coil X: <br/> ·\tIf X moves towards Y: Counterclockwise in Y. <br/> ·\tIf X moves away from Y: Clockwise in Y. <br/>  <br/> ∴ The figure that depicts the direction of the induced current in coil y is: <br/>  <br/> <img src=\"2009/o3.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "ELECTROMAGNETIC INDUCTION : INDUCTION COIL"}, {"id": "objective>Physics>2009>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  From the diagram above, if the potential difference across the resistor, capacitor and inductor are 80V, 110V and 40V respectively, the effective potential difference is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">116.3V\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50.0V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">230.0V\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">106.3V</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V = √ (V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">R</span>)+(V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span>-V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> V = √ (80)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>+(40-110)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> V = √6400+(-70)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> V = √1130 <br/>  = V = 106.3v</div>", "topic": "SIMPLE A. C. CIRCUITS"}, {"id": "objective>Physics>2009>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cancerous cells can be destroyed by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ultraviolet rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alpha particles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">x-rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infrared rays</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Radiation therapy uses high-energy radiation to shrink tumors and kill cancer cells. X-rays, gamma rays, and charged particles are types of radiation used for cancer treatment.</div>", "topic": "ELEMENTARY MODERN PHYSICS : X-RAYS"}, {"id": "objective>Physics>2009>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the decay constant of a radioactive substance is 0.231s-1, the half-life is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.00s\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.12s\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.33s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.50s</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">λ = 0.693/t, 0.231 = 0.693/t  <br/> t = 0.693/0.231 = 3.00s</div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2009>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A piece of radioactive material contains 1020 atoms. If the half life of the material is 20 seconds, the number of disintegrations in the first second is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.47 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">18</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">20</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.47 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">20</span>\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">18</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The number of disintegrations in the first second is given by the formula N = N0 * λ, where N0 is the initial number of atoms and λ is the decay constant. The decay constant can be calculated from the half-life using the formula λ = ln(2)/T, where T is the half-life. Substituting the given values gives λ = ln(2)/20 = 0.0347s^-1 and N = 1020 * 0.0347 = 3.47 x 10^18. Therefore, the number of disintegrations in the first second is 3.47 x 10^18.</div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2009>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Thermionic emission is the process whereby</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rays are produced </div>", "<div style=\"font-family:Cambria;font-size:17px;\">holes are produced </div>", "<div style=\"font-family:Cambria;font-size:17px;\">x-rays are produced</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrons leave a hot element</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thermionic emission is the thermally induced flow of charge carriers from a surface or over a potential-energy barrier. This occurs because the thermal energy given to the carrier overcomes the work function of the material.</div>", "topic": "ELEMENTARY MODERN PHYSICS : THERMIONIC EMISSIONS"}, {"id": "objective>Physics>2009>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following can conduct electricity owing to the presence of the free mobile electrons?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Germanium\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Silicon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Grapefruit\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Copper</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Copper is a good conductor of electricity due to the presence of free mobile electrons. In metals like copper, some electrons are not bound to atoms and can move freely within the metal, conducting electric current. Germanium and Silicon are semiconductors, they do not have free mobile electrons. Grapefruit is a fruit and does not conduct electricity.</div>", "topic": "INTRODUCTORY ELECTRONICS : METALS, SEMICONDUCTORS AND INSULATORS"}, {"id": "objective>Physics>2009>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a pentavalent impurity is added to a pure semiconductor, it becomes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a p-type semiconductor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an n-type semiconductor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an insulator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an intrinsic semiconductor</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Doping is the process of adding impurities to intrinsic semiconductors to alter their properties. Normally Trivalent and Pentavalent elements are used to dope Silicon and Germanium. When a intrinsic semiconductor is doped with Trivalent impurity it becomes a P-Type semiconductors. The P stands for Positive, which means the semiconductor is rich in holes or Positive charged ions. When we dope intrinsic material with Pentavalent impurities we get N-Type semiconductor, where N stands for Negative. N-type semiconductors have Negative charged ions or in other words have excess electrons.</div>", "topic": "INTRODUCTORY ELECTRONICS : N-TYPE AND P-TYPE SEMI-CONDUCTORS"}];
